//! moment.js locale configuration
//! locale : Malay [ms-my]
//! note : DEPRECATED, the correct one is [ms]
//! author : Weldan Jamili : https://github.com/weldan

import moment from '@lark/moment-timezone-polyfill'

export default moment.defineLocale('ms-MY', {
  months:
    'Januari_Februari_Mac_April_Mei_Jun_Julai_Ogos_September_Oktober_November_Disember'.split(
      '_'
    ),
  monthsShort: 'Jan_Feb_Mac_Apr_Mei_Jun_Jul_Ogo_Sep_Okt_Nov_Dis'.split('_'),
  weekdays: 'Ahad_Isnin_Selasa_Rabu_Khamis_Jumaat_Sabtu'.split('_'),
  weekdaysShort: 'Aha_Isn_Sel_Rab_Kha_Jum_Sab'.split('_'),
  weekdaysMin: 'A_I_S_R_K_J_S'.split('_'),
  longDateFormat: {
    LT: 'HH:mm',
    LTS: 'HH.mm.ss',
    L: 'DD/MM/YYYY',
    LL: 'D MMMM YYYY',
    LLL: 'D MMMM YYYY HH.mm',
    LLLL: 'dddd, D MMMM YYYY HH.mm',
  },

  // moment 定义了四个，此处选择缩写两个
  meridiemParse: /PG|PTG/,
  meridiemHour: function (hour, meridiem) {
    if (hour === 12) {
      hour = 0
    }
    let returnString
    if (meridiem === 'PG') {
      returnString = hour
    } else if (meridiem === 'PTG') {
      returnString = hour + 12
    }
    return returnString
  },
  meridiem: function (hour, minute, isLower) {
    const hm = hour * 100 + minute
    let returnString
    if (hm < 1200) {
      returnString = 'PG'
    } else {
      returnString = 'PTG'
    }

    return returnString
  },
  calendar: {
    sameDay: '[Hari ini] LT',
    nextDay: '[Esok] LT',
    nextWeek: 'dddd LT',
    lastDay: '[Semalam] LT',
    lastWeek: 'dddd [lepas] LT',
    sameElse: 'L',
  },
  relativeTime: {
    future: 'dalam %s',
    past: '%s yang lepas',
    s: 'beberapa saat',
    ss: '%d saat',
    m: 'seminit',
    mm: '%d minit',
    h: 'sejam',
    hh: '%d jam',
    d: 'sehari',
    dd: '%d hari',
    M: 'sebulan',
    MM: '%d bulan',
    y: 'setahun',
    yy: '%d tahun',
  },
  week: {
    dow: 1, // Monday is the first day of the week.
    doy: 7, // The week that contains Jan 7th is the first week of the year.
  },
} as any as moment.LocaleSpecification)
